I cannot directly generate a 3D file (like .obj or .fbx) or render a video file. However, I can provide you with the **complete code** to generate and render a 3D house in your browser using **Three.js**.

You can copy the code below, save it as an `.html` file (e.g., `house.html`), and open it in any modern web browser to see the result.

### 3D House Generator (HTML + Three.js)

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>3D House Render</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">Click & Drag to Rotate | Scroll to Zoom</div>

    <!-- Import Three.js from CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // 1. Scene Setup
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(60, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 20);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true;
        document.body.appendChild(renderer.domElement);

        // 2. Controls
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;

        // 3. Lighting
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // 4. Materials
        const wallMaterial = new THREE.MeshStandardMaterial({ color: 0xeeeeee });
        const roofMaterial = new THREE.MeshStandardMaterial({ color: 0x8B4513 });
        const windowMaterial = new THREE.MeshStandardMaterial({ color: 0x87CEEB, emissive: 0x87CEEB, emissiveIntensity: 0.5 });
        const doorMaterial = new THREE.MeshStandardMaterial({ color: 0x5c3a21 });
        const grassMaterial = new THREE.MeshStandardMaterial({ color: 0x4caf50 });

        // 5. Building the House
        const houseGroup = new THREE.Group();

        // Floor
        const floorGeo = new THREE.BoxGeometry(10, 1, 10);
        const floor = new THREE.Mesh(floorGeo, grassMaterial);
        floor.position.y = -0.5;
        floor.receiveShadow = true;
        houseGroup.add(floor);

        // Main Body
        const bodyGeo = new THREE.BoxGeometry(8, 6, 8);
        const body = new THREE.Mesh(bodyGeo, wallMaterial);
        body.position.y = 3;
        body.castShadow = true;
        body.receiveShadow = true;
        houseGroup.add(body);

        // Roof
        const roofGeo = new THREE.ConeGeometry(7, 4, 4);
        const roof = new THREE.Mesh(roofGeo, roofMaterial);
        roof.position.y = 8;
        roof.rotation.y = Math.PI / 4;
        roof.castShadow = true;
        houseGroup.add(roof);

        // Windows
        function createWindow(x, z, rotY) {
            const winGeo = new THREE.BoxGeometry(1.5, 1.5, 0.2);
            const win = new THREE.Mesh(winGeo, windowMaterial);
            win.position.set(x, 5, z);
            win.rotation.y = rotY;
            houseGroup.add(win);
        }
        createWindow(2.5, 2.5, 0);
        createWindow(-2.5, 2.5, 0);
        createWindow(2.5, -2.5, 0);
        createWindow(-2.5, -2.5, 0);

        // Door
        const doorGeo = new THREE.BoxGeometry(2, 3, 0.2);
        const door = new THREE.Mesh(doorGeo, doorMaterial);
        door.position.set(0, 3, 4.1);
        door.castShadow = true;
        houseGroup.add(door);

        // Porch
        const porchGeo = new THREE.BoxGeometry(9, 0.5, 3);
        const porch = new THREE.Mesh(porchGeo, new THREE.MeshStandardMaterial({color: 0x8B4513}));
        porch.position.set(0, 0.25, 4.75);
        porch.receiveShadow = true;
        houseGroup.add(porch);

        scene.add(houseGroup);

        // 6. Trees (Simple Cylinders + Cones)
        function createTree(x, z) {
            const trunkGeo = new THREE.CylinderGeometry(0.5, 0.5, 2);
            const trunk = new THREE.Mesh(trunkGeo, new THREE.MeshStandardMaterial({color: 0x8B4513}));
            trunk.position.set(x, 1, z);
            trunk.castShadow = true;

            const leavesGeo = new THREE.ConeGeometry(2, 4, 8);
            const leaves = new THREE.Mesh(leavesGeo, new THREE.MeshStandardMaterial({color: 0x228B22}));
            leaves.position.set(x, 3, z);
            leaves.castShadow = true;

            return new THREE.Group().add(trunk).add(leaves);
        }

        const tree1 = createTree(-8, -5);
        const tree2 = createTree(8, -8);
        const tree3 = createTree(-6, 8);
        scene.add(tree1);
        scene.add(tree2);
        scene.add(tree3);

        // 7. Animation Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }

        // Handle Resize
        window.addEventListener('resize', () => {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        });

        animate();
    </script>
</body>
</html>
```

### How to use this:
1.  **Copy** the code block above.
2.  Create a new file on your computer named `house.html`.
3.  **Paste** the code into that file and save it.
4.  **Double-click** `house.html` to open it in Chrome, Firefox, or Edge.

### Features included in this render:
*   **Procedural Generation:** The house is built using geometric primitives (Boxes, Cones, Cylinders).
*   **Lighting & Shadows:** Includes directional sunlight and ambient light with shadow casting enabled.
*   **Interactivity:** You can **click and drag** to rotate around the house and **scroll** to zoom in/out.
*   **Environment:** Includes a grassy floor, a sky-blue background, fog for depth, and simple trees.
